#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Level;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Enemies;
using MVZ2.GameContent.Seeds;
using MVZ2.GameContent.Stages;
using MVZ2Logic;
using MVZ2Logic.IZombie;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Level;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.IZombie
{
    [IZombieLayoutDefinition(VanillaIZombieLayoutNames.HatTrick)]
    public class HatTrick : IZombieLayoutDefinition
    {
        public HatTrick(string nsp, string name) : base(nsp, name, 5)
        {
            Blueprints = new NamespaceID[]
            {
                VanillaEnemyID.mesmerizer,
                VanillaEnemyID.hellChariot,
            };
        }
        public override void Fill(IIZombieMap map, RandomGenerator rng)
        {
            var level = map.Level;

            SpawnAt(level, 0, 0, VanillaContraptionID.errorBlock);
            SpawnAt(level, 0, 1, VanillaContraptionID.magichest);
            SpawnAt(level, 0, 2, VanillaContraptionID.soulFurnace);
            SpawnAt(level, 0, 3, VanillaContraptionID.blackHoleBomb);
            SpawnAt(level, 0, 4, VanillaContraptionID.silvenser);
            SpawnAt(level, 0, 4, VanillaContraptionID.stoneShield);

            SpawnAt(level, 1, 0, VanillaContraptionID.errorBlock);
            SpawnAt(level, 1, 1, VanillaContraptionID.magichest);
            SpawnAt(level, 1, 2, VanillaContraptionID.blackHoleBomb);
            SpawnAt(level, 1, 3, VanillaContraptionID.soulFurnace);
            SpawnAt(level, 1, 4, VanillaContraptionID.furnace);
            SpawnAt(level, 1, 4, VanillaContraptionID.stoneShield);

            SpawnAt(level, 2, 0, VanillaContraptionID.errorBlock);
            SpawnAt(level, 2, 1, VanillaContraptionID.magichest);
            SpawnAt(level, 2, 2, VanillaContraptionID.lightningOrb);
            SpawnAt(level, 2, 3, VanillaContraptionID.furnace);
            SpawnAt(level, 2, 4, VanillaContraptionID.furnace);
            SpawnAt(level, 2, 4, VanillaContraptionID.stoneShield);

            SpawnAt(level, 3, 0, VanillaContraptionID.soulFurnace);
            SpawnAt(level, 3, 1, VanillaContraptionID.magichest);
            SpawnAt(level, 3, 2, VanillaContraptionID.diamondSpikes);
            SpawnAt(level, 3, 3, VanillaContraptionID.diamondSpikes);
            SpawnAt(level, 3, 4, VanillaContraptionID.drivenser);
            SpawnAt(level, 3, 4, VanillaContraptionID.stoneShield);

            SpawnAt(level, 4, 0, VanillaContraptionID.tnt);
            SpawnAt(level, 4, 1, VanillaContraptionID.glowstone);
            SpawnAt(level, 4, 2, VanillaContraptionID.furnace);
            SpawnAt(level, 4, 3, VanillaContraptionID.lightningOrb);
            SpawnAt(level, 4, 4, VanillaContraptionID.elasticCloud);

            SpawnAt(level, 5, 3, VanillaContraptionID.gravityPad);

            //SpawnAt(level, 3, 2, VanillaContraptionID.redline);

            //var rlX = level.GetColumnX(3);       // 죗璘긋鍍，宅깃硫븐窟寧鈴  
            //var rlZ = level.GetLaneCenterZ(2);   // lane 3 돨櫓懃  
            //var rlY = level.GetGroundY(rlX, rlZ);

            //level.Spawn(VanillaContraptionID.redline, new Vector3(rlX, rlY, rlZ), null);

            var buffDef = level.Content.GetBuffDefinition<DebugNoRechargeBuff>();
            if (!level.HasBuff(buffDef))
            {
                level.AddBuff(buffDef);
            }

        }
        private void SpawnAt(LevelEngine level, int column, int lane, NamespaceID entityID)
        {
            var x = level.GetEntityColumnX(column);
            var z = level.GetEntityLaneZ(lane);
            var y = level.GetGroundY(x, z);
            level.Spawn(entityID, new Vector3(x, y, z), null);
        }
    }
}
